def range_summary(nums):
    if not nums:
        return ''
    nums.sort()
    ranges = []
    start = nums[0]
    for i in range(1, len(nums)):
        if nums[i] != nums[i-1]:
            if start == nums[i-1]:
                ranges.append(str(start))
            else:
                ranges.append(f"{start}-{nums[i-1]}")
            start = nums[i]
    ranges.append(f"{start}")  # Append the last range
    return ','.join(ranges)
